class IntStack {
  private final java.util.ArrayList<Integer> data = new java.util.ArrayList<>();
  void push(int value) { data.add(value); }
  int peek() { return data.get(data.size() - 1); }
  int pop() {
    if (data.isEmpty()) throw new IllegalStateException("underflow");
    return data.remove(data.size() - 1);
  }
}
